diff --git a/test/cache-options.test.js b/test/cache-options.test.js
new file mode 100644
index 0000000..27497f8
--- /dev/null
+++ b/test/cache-options.test.js
@@ -0,0 +1,431 @@
+import cacache from 'cacache';
+import findCacheDir from 'find-cache-dir';
+import UglifyJsPlugin from '../src/index';
+import {
+  PluginEnvironment,
+  createCompiler,
+  compile,
+  cleanErrorStack,
+} from './helpers';
+
+const cacheDir = findCacheDir({ name: 'uglifyjs-webpack-plugin' });
+
+describe('when options.cache', () => {
+  const assets = {
+    'test.js': {
+      source: () => 'function test(foo) { foo = 1; }',
+    },
+    'test1.js': {
+      source: () => 'function test1(foo) { foo = 1; }',
+    },
+    'test2.js': {
+      source: () => 'function test2(foo) { foo = 1; }',
+    },
+    'test3.js': {
+      source: () => 'function test3(foo) { foo = 1; }',
+    },
+  };
+
+  describe('false', () => {
+    let eventBindings;
+    let eventBinding;
+
+    beforeAll(() => cacache.rm.all(cacheDir));
+
+    beforeEach(() => {
+      const pluginEnvironment = new PluginEnvironment();
+      const compilerEnv = pluginEnvironment.getEnvironmentStub();
+      compilerEnv.context = '';
+
+      const plugin = new UglifyJsPlugin({
+        cache: false,
+      });
+      plugin.apply(compilerEnv);
+      eventBindings = pluginEnvironment.getEventBindings();
+    });
+
+    it('binds one event handler', () => {
+      expect(eventBindings.length).toBe(1);
+    });
+
+    describe('compilation handler', () => {
+      beforeEach(() => {
+        [eventBinding] = eventBindings;
+      });
+
+      it('binds to compilation event', () => {
+        expect(eventBinding.name).toBe('compilation');
+      });
+
+      describe('when called', () => {
+        let chunkPluginEnvironment;
+        let compilationEventBindings;
+        let compilationEventBinding;
+        let compilation;
+        let callback;
+
+        beforeEach(() => {
+          chunkPluginEnvironment = new PluginEnvironment();
+          compilation = chunkPluginEnvironment.getEnvironmentStub();
+          compilation.assets = Object.assign({}, assets);
+          compilation.errors = [];
+
+          eventBinding.handler(compilation);
+          compilationEventBindings = chunkPluginEnvironment.getEventBindings();
+        });
+
+        it('binds one event handler', () => {
+          expect(compilationEventBindings.length).toBe(1);
+        });
+
+        describe('optimize-chunk-assets handler', () => {
+          beforeEach(() => {
+            [compilationEventBinding] = compilationEventBindings;
+          });
+
+          it('binds to optimize-chunk-assets event', () => {
+            expect(compilationEventBinding.name).toEqual('optimize-chunk-assets');
+          });
+
+          it('only calls callback once', (done) => {
+            callback = jest.fn();
+            compilationEventBinding.handler([''], () => {
+              callback();
+              expect(callback.mock.calls.length).toBe(1);
+              done();
+            });
+          });
+
+          it('cache files', (done) => {
+            const files = ['test.js', 'test1.js', 'test2.js', 'test3.js'];
+
+            cacache.get = jest.fn(cacache.get);
+            cacache.put = jest.fn(cacache.put);
+
+            compilationEventBinding.handler([{
+              files,
+            }], () => {
+              // Cache disabled so we don't run `get` or `put`
+              expect(cacache.get.mock.calls.length).toBe(0);
+              expect(cacache.put.mock.calls.length).toBe(0);
+
+              cacache
+                .ls(cacheDir)
+                .then((cacheEntriesList) => {
+                  const cacheEntriesListKeys = Object.keys(cacheEntriesList);
+
+                  expect(cacheEntriesListKeys.length).toBe(0);
+                  done();
+                });
+            });
+          });
+        });
+      });
+    });
+
+    it('matches snapshot', () => {
+      const compiler = createCompiler();
+      new UglifyJsPlugin({ cache: true }).apply(compiler);
+
+      return compile(compiler)
+        .then((stats) => {
+          const errors = stats.compilation.errors.map(cleanErrorStack);
+          const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+          expect(errors).toMatchSnapshot('cache `false`: errors');
+          expect(warnings).toMatchSnapshot('cache `false`: warnings');
+
+          for (const file in stats.compilation.assets) {
+            if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+              expect(stats.compilation.assets[file].source()).toMatchSnapshot(`cache \`false\`: asset ${file}`);
+            }
+          }
+        });
+    });
+  });
+
+  describe('true', () => {
+    let eventBindings;
+    let eventBinding;
+
+    beforeAll(() => cacache.rm.all(cacheDir));
+
+    beforeEach(() => {
+      const pluginEnvironment = new PluginEnvironment();
+      const compilerEnv = pluginEnvironment.getEnvironmentStub();
+      compilerEnv.context = '';
+
+      const plugin = new UglifyJsPlugin({
+        cache: true,
+      });
+      plugin.apply(compilerEnv);
+      eventBindings = pluginEnvironment.getEventBindings();
+    });
+
+    it('binds one event handler', () => {
+      expect(eventBindings.length).toBe(1);
+    });
+
+    describe('compilation handler', () => {
+      beforeEach(() => {
+        [eventBinding] = eventBindings;
+      });
+
+      it('binds to compilation event', () => {
+        expect(eventBinding.name).toBe('compilation');
+      });
+
+      describe('when called', () => {
+        let chunkPluginEnvironment;
+        let compilationEventBindings;
+        let compilationEventBinding;
+        let compilation;
+        let callback;
+
+        beforeEach(() => {
+          chunkPluginEnvironment = new PluginEnvironment();
+          compilation = chunkPluginEnvironment.getEnvironmentStub();
+          compilation.assets = Object.assign({}, assets);
+          compilation.errors = [];
+
+          eventBinding.handler(compilation);
+          compilationEventBindings = chunkPluginEnvironment.getEventBindings();
+        });
+
+        it('binds one event handler', () => {
+          expect(compilationEventBindings.length).toBe(1);
+        });
+
+        describe('optimize-chunk-assets handler', () => {
+          beforeEach(() => {
+            [compilationEventBinding] = compilationEventBindings;
+          });
+
+          it('binds to optimize-chunk-assets event', () => {
+            expect(compilationEventBinding.name).toEqual('optimize-chunk-assets');
+          });
+
+          it('only calls callback once', (done) => {
+            callback = jest.fn();
+            compilationEventBinding.handler([''], () => {
+              callback();
+              expect(callback.mock.calls.length).toBe(1);
+              done();
+            });
+          });
+
+          it('cache files', (done) => {
+            const files = ['test.js', 'test1.js', 'test2.js', 'test3.js'];
+
+            cacache.get = jest.fn(cacache.get);
+            cacache.put = jest.fn(cacache.put);
+
+            compilationEventBinding.handler([{
+              files,
+            }], () => {
+              // Try to found cached files, but we don't have their in cache
+              expect(cacache.get.mock.calls.length).toBe(4);
+              // Put files in cache
+              expect(cacache.put.mock.calls.length).toBe(4);
+
+              cacache
+                .ls(cacheDir)
+                .then((cacheEntriesList) => {
+                  const cacheEntriesListKeys = Object.keys(cacheEntriesList);
+
+                  // Make sure that we cached files
+                  expect(cacheEntriesListKeys.length).toBe(files.length);
+                  cacheEntriesListKeys.forEach((cacheJSONEntry) => {
+                    const cacheEntry = JSON.parse(cacheJSONEntry);
+
+                    expect([cacheEntry.path, cacheEntry.input])
+                      .toMatchSnapshot(`cache \`true\`: cached entry ${cacheEntry.path}`);
+                  });
+
+                  // Reset compilation assets and mocks
+                  compilation.assets = Object.assign({}, assets);
+                  compilation.errors = [];
+
+                  cacache.get.mockClear();
+                  cacache.put.mockClear();
+
+                  compilationEventBinding.handler([{
+                    files,
+                  }], () => {
+                    // Now we have cached files so we get their and don't put
+                    expect(cacache.get.mock.calls.length).toBe(4);
+                    expect(cacache.put.mock.calls.length).toBe(0);
+
+                    done();
+                  });
+                });
+            });
+          });
+        });
+      });
+    });
+
+    it('matches snapshot', () => {
+      const compiler = createCompiler();
+      new UglifyJsPlugin({ cache: true }).apply(compiler);
+
+      return compile(compiler)
+        .then((stats) => {
+          const errors = stats.compilation.errors.map(cleanErrorStack);
+          const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+          expect(errors).toMatchSnapshot('cache `true`: errors');
+          expect(warnings).toMatchSnapshot('cache `true`: warnings');
+
+          for (const file in stats.compilation.assets) {
+            if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+              expect(stats.compilation.assets[file].source()).toMatchSnapshot(`cache \`true\`: asset ${file}`);
+            }
+          }
+        });
+    });
+  });
+
+  describe('string', () => {
+    const othercacheDir = findCacheDir({ name: 'other-cache-directory' });
+    let eventBindings;
+    let eventBinding;
+
+    beforeAll(() => cacache.rm.all(othercacheDir));
+
+    beforeEach(() => {
+      const pluginEnvironment = new PluginEnvironment();
+      const compilerEnv = pluginEnvironment.getEnvironmentStub();
+      compilerEnv.context = '';
+
+      const plugin = new UglifyJsPlugin({
+        cache: othercacheDir,
+      });
+      plugin.apply(compilerEnv);
+      eventBindings = pluginEnvironment.getEventBindings();
+    });
+
+    it('binds one event handler', () => {
+      expect(eventBindings.length).toBe(1);
+    });
+
+    describe('compilation handler', () => {
+      beforeEach(() => {
+        [eventBinding] = eventBindings;
+      });
+
+      it('binds to compilation event', () => {
+        expect(eventBinding.name).toBe('compilation');
+      });
+
+      describe('when called', () => {
+        let chunkPluginEnvironment;
+        let compilationEventBindings;
+        let compilationEventBinding;
+        let compilation;
+        let callback;
+
+        beforeEach(() => {
+          chunkPluginEnvironment = new PluginEnvironment();
+          compilation = chunkPluginEnvironment.getEnvironmentStub();
+          compilation.assets = Object.assign({}, assets);
+          compilation.errors = [];
+
+          eventBinding.handler(compilation);
+          compilationEventBindings = chunkPluginEnvironment.getEventBindings();
+        });
+
+        it('binds one event handler', () => {
+          expect(compilationEventBindings.length).toBe(1);
+        });
+
+        describe('optimize-chunk-assets handler', () => {
+          beforeEach(() => {
+            [compilationEventBinding] = compilationEventBindings;
+          });
+
+          it('binds to optimize-chunk-assets event', () => {
+            expect(compilationEventBinding.name).toEqual('optimize-chunk-assets');
+          });
+
+          it('only calls callback once', (done) => {
+            callback = jest.fn();
+            compilationEventBinding.handler([''], () => {
+              callback();
+              expect(callback.mock.calls.length).toBe(1);
+              done();
+            });
+          });
+
+          it('cache files', (done) => {
+            const files = ['test.js', 'test1.js', 'test2.js', 'test3.js'];
+
+            cacache.get = jest.fn(cacache.get);
+            cacache.put = jest.fn(cacache.put);
+
+            compilationEventBinding.handler([{
+              files,
+            }], () => {
+              // Try to found cached files, but we don't have their in cache
+              expect(cacache.get.mock.calls.length).toBe(4);
+              // Put files in cache
+              expect(cacache.put.mock.calls.length).toBe(4);
+
+              cacache
+                .ls(othercacheDir)
+                .then((cacheEntriesList) => {
+                  const cacheEntriesListKeys = Object.keys(cacheEntriesList);
+
+                  // Make sure that we cached files
+                  expect(cacheEntriesListKeys.length).toBe(files.length);
+                  cacheEntriesListKeys.forEach((cacheJSONEntry) => {
+                    const cacheEntry = JSON.parse(cacheJSONEntry);
+
+                    expect([cacheEntry.path, cacheEntry.input])
+                      .toMatchSnapshot(`cache \`string\`: cached entry ${cacheEntry.path}`);
+                  });
+
+                  // Reset compilation assets and mocks
+                  compilation.assets = Object.assign({}, assets);
+                  compilation.errors = [];
+
+                  cacache.get.mockClear();
+                  cacache.put.mockClear();
+
+                  compilationEventBinding.handler([{
+                    files,
+                  }], () => {
+                    // Now we have cached files so we get their and don't put
+                    expect(cacache.get.mock.calls.length).toBe(4);
+                    expect(cacache.put.mock.calls.length).toBe(0);
+
+                    done();
+                  });
+                });
+            });
+          });
+        });
+      });
+    });
+
+    it('matches snapshot', () => {
+      const compiler = createCompiler();
+      new UglifyJsPlugin({ cache: othercacheDir }).apply(compiler);
+
+      return compile(compiler)
+        .then((stats) => {
+          const errors = stats.compilation.errors.map(cleanErrorStack);
+          const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+          expect(errors).toMatchSnapshot('cache `string`: errors');
+          expect(warnings).toMatchSnapshot('cache `string`: warnings');
+
+          for (const file in stats.compilation.assets) {
+            if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+              expect(stats.compilation.assets[file].source()).toMatchSnapshot(`cache \`string\`: asset ${file}`);
+            }
+          }
+        });
+    });
+  });
+});

diff --git a/test/ecma.test.js b/test/ecma.test.js
new file mode 100644
index 0000000..b26ac4c
--- /dev/null
+++ b/test/ecma.test.js
@@ -0,0 +1,192 @@
+import UglifyJsPlugin from '../src/index';
+import {
+  cleanErrorStack,
+  createCompiler,
+  compile,
+} from './helpers';
+
+describe('when applied with uglifyOptions.ecma', () => {
+  it('matches snapshot for import and export', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/import-export/entry.js`,
+      output: {
+        path: `${__dirname}/dist-import-export`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      uglifyOptions: {
+        ecma: 5,
+        mangle: false,
+        warnings: true,
+        output: {
+          beautify: true,
+          comments: false,
+        },
+      },
+    }).apply(compiler);
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('import-export: errors');
+      expect(warnings).toMatchSnapshot('import-export: warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(`import-export: ${file}`);
+        }
+      }
+    });
+  });
+
+  it('matches snapshot for ecma 5', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/ecma-5/entry.js`,
+      output: {
+        path: `${__dirname}/dist-ecma-5`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      uglifyOptions: {
+        ecma: 5,
+        mangle: false,
+        warnings: true,
+        output: {
+          beautify: true,
+          comments: false,
+        },
+      },
+    }).apply(compiler);
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('ecma 5: errors');
+      expect(warnings).toMatchSnapshot('ecma 5: warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(`ecma 5: ${file}`);
+        }
+      }
+    });
+  });
+
+  it('matches snapshot for ecma 6', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/ecma-6/entry.js`,
+      output: {
+        path: `${__dirname}/dist-ecma-6`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      uglifyOptions: {
+        ecma: 6,
+        mangle: false,
+        warnings: true,
+        output: {
+          beautify: true,
+          comments: false,
+        },
+      },
+    }).apply(compiler);
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('ecma 6: errors');
+      expect(warnings).toMatchSnapshot('ecma 6: warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(`ecma 6: ${file}`);
+        }
+      }
+    });
+  });
+
+  it('matches snapshot for ecma 7', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/ecma-7/entry.js`,
+      output: {
+        path: `${__dirname}/dist-ecma-7`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+    new UglifyJsPlugin({
+      uglifyOptions: {
+        ecma: 7,
+        mangle: false,
+        warnings: true,
+        output: {
+          beautify: true,
+          comments: false,
+        },
+      },
+    }).apply(compiler);
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('ecma 7: errors');
+      expect(warnings).toMatchSnapshot('ecma 7: warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(`ecma 7: ${file}`);
+        }
+      }
+    });
+  });
+
+  it('matches snapshot for ecma 8', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/ecma-8/entry.js`,
+      output: {
+        path: `${__dirname}/dist-ecma-8`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      uglifyOptions: {
+        ecma: 8,
+        mangle: false,
+        warnings: true,
+        output: {
+          beautify: true,
+          comments: false,
+        },
+      },
+    }).apply(compiler);
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('ecma 8: errors');
+      expect(warnings).toMatchSnapshot('ecma 8: warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(`ecma 8: ${file}`);
+        }
+      }
+    });
+  });
+});

