index 7ce6249..6a1f730 100644
--- a/test/cache-options.test.js
+++ b/test/cache-options.test.js
@@ -436,4 +436,169 @@ describe('when options.cache', () => {
         });
     });
   });
+
+  describe('with cacheKey option', () => {
+    let eventBindings;
+    let eventBinding;
+
+    beforeAll(() => cacache.rm.all(cacheDir));
+
+    afterAll(() => cacache.rm.all(cacheDir));
+
+    beforeEach(() => {
+      const pluginEnvironment = new PluginEnvironment();
+      const compilerEnv = pluginEnvironment.getEnvironmentStub();
+      compilerEnv.context = '';
+
+      const plugin = new UglifyJsPlugin({
+        cache: true,
+        cacheKeys: (defaultCacheKeys, file) => {
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheKey = 1;
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheKeyBasedOnFile = `file-${file}`;
+
+          return defaultCacheKeys;
+        },
+      });
+      plugin.apply(compilerEnv);
+      eventBindings = pluginEnvironment.getEventBindings();
+    });
+
+    it('binds one event handler', () => {
+      expect(eventBindings.length).toBe(1);
+    });
+
+    describe('compilation handler', () => {
+      beforeEach(() => {
+        [eventBinding] = eventBindings;
+      });
+
+      it('binds to compilation event', () => {
+        expect(eventBinding.name).toBe('compilation');
+      });
+
+      describe('when called', () => {
+        let chunkPluginEnvironment;
+        let compilationEventBindings;
+        let compilationEventBinding;
+        let compilation;
+        let callback;
+
+        beforeEach(() => {
+          chunkPluginEnvironment = new PluginEnvironment();
+          compilation = chunkPluginEnvironment.getEnvironmentStub();
+          compilation.assets = Object.assign({}, assets);
+          compilation.errors = [];
+
+          eventBinding.handler(compilation);
+          compilationEventBindings = chunkPluginEnvironment.getEventBindings();
+        });
+
+        it('binds one event handler', () => {
+          expect(compilationEventBindings.length).toBe(1);
+        });
+
+        describe('optimize-chunk-assets handler', () => {
+          beforeEach(() => {
+            [compilationEventBinding] = compilationEventBindings;
+          });
+
+          it('binds to optimize-chunk-assets event', () => {
+            expect(compilationEventBinding.name).toEqual('optimize-chunk-assets');
+          });
+
+          it('only calls callback once', (done) => {
+            callback = jest.fn();
+            compilationEventBinding.handler([''], () => {
+              callback();
+              expect(callback.mock.calls.length).toBe(1);
+              done();
+            });
+          });
+
+          it('cache files', (done) => {
+            const files = ['test.js', 'test1.js', 'test2.js', 'test3.js'];
+
+            cacache.get = jest.fn(cacache.get);
+            cacache.put = jest.fn(cacache.put);
+
+            compilationEventBinding.handler([{
+              files,
+            }], () => {
+              // Try to found cached files, but we don't have their in cache
+              expect(cacache.get.mock.calls.length).toBe(4);
+              // Put files in cache
+              expect(cacache.put.mock.calls.length).toBe(4);
+
+              cacache
+                .ls(cacheDir)
+                .then((cacheEntriesList) => {
+                  const cacheKeys = Object.keys(cacheEntriesList);
+
+                  // Make sure that we cached files
+                  expect(cacheKeys.length).toBe(files.length);
+                  cacheKeys.forEach((cacheEntry) => {
+                    // eslint-disable-next-line no-new-func
+                    const cacheEntryOptions = new Function(`'use strict'\nreturn ${cacheEntry}`)();
+
+                    expect(cacheEntryOptions.myCacheKey).toBe(1);
+                    expect(cacheEntryOptions.myCacheKeyBasedOnFile).toMatch(/file-test(.)?\.js/);
+                    expect([cacheEntryOptions.path, cacheEntryOptions.hash])
+                      .toMatchSnapshot(cacheEntryOptions.path);
+                  });
+
+                  // Reset compilation assets and mocks
+                  compilation.assets = Object.assign({}, assets);
+                  compilation.errors = [];
+
+                  cacache.get.mockClear();
+                  cacache.put.mockClear();
+
+                  compilationEventBinding.handler([{
+                    files,
+                  }], () => {
+                    // Now we have cached files so we get their and don't put
+                    expect(cacache.get.mock.calls.length).toBe(4);
+                    expect(cacache.put.mock.calls.length).toBe(0);
+
+                    done();
+                  });
+                });
+            });
+          });
+        });
+      });
+    });
+
+    it('matches snapshot', () => {
+      const compiler = createCompiler();
+      new UglifyJsPlugin({
+        cache: true,
+        cacheKeys: (defaultCacheKeys, file) => {
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheKey = 1;
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheLeyBasedOnFile = `file-${file}`;
+
+          return defaultCacheKeys;
+        },
+      }).apply(compiler);
+
+      return compile(compiler)
+        .then((stats) => {
+          const errors = stats.compilation.errors.map(cleanErrorStack);
+          const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+          expect(errors).toMatchSnapshot('errors');
+          expect(warnings).toMatchSnapshot('warnings');
+
+          for (const file in stats.compilation.assets) {
+            if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+              expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+            }
+          }
+        });
+    });
+  });
 });

diff --git a/test/cache-options.test.js b/test/cache-options.test.js
index 7ce6249..6a1f730 100644
--- a/test/cache-options.test.js
+++ b/test/cache-options.test.js
@@ -436,4 +436,169 @@ describe('when options.cache', () => {
         });
     });
   });
+
+  describe('with cacheKey option', () => {
+    let eventBindings;
+    let eventBinding;
+
+    beforeAll(() => cacache.rm.all(cacheDir));
+
+    afterAll(() => cacache.rm.all(cacheDir));
+
+    beforeEach(() => {
+      const pluginEnvironment = new PluginEnvironment();
+      const compilerEnv = pluginEnvironment.getEnvironmentStub();
+      compilerEnv.context = '';
+
+      const plugin = new UglifyJsPlugin({
+        cache: true,
+        cacheKeys: (defaultCacheKeys, file) => {
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheKey = 1;
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheKeyBasedOnFile = `file-${file}`;
+
+          return defaultCacheKeys;
+        },
+      });
+      plugin.apply(compilerEnv);
+      eventBindings = pluginEnvironment.getEventBindings();
+    });
+
+    it('binds one event handler', () => {
+      expect(eventBindings.length).toBe(1);
+    });
+
+    describe('compilation handler', () => {
+      beforeEach(() => {
+        [eventBinding] = eventBindings;
+      });
+
+      it('binds to compilation event', () => {
+        expect(eventBinding.name).toBe('compilation');
+      });
+
+      describe('when called', () => {
+        let chunkPluginEnvironment;
+        let compilationEventBindings;
+        let compilationEventBinding;
+        let compilation;
+        let callback;
+
+        beforeEach(() => {
+          chunkPluginEnvironment = new PluginEnvironment();
+          compilation = chunkPluginEnvironment.getEnvironmentStub();
+          compilation.assets = Object.assign({}, assets);
+          compilation.errors = [];
+
+          eventBinding.handler(compilation);
+          compilationEventBindings = chunkPluginEnvironment.getEventBindings();
+        });
+
+        it('binds one event handler', () => {
+          expect(compilationEventBindings.length).toBe(1);
+        });
+
+        describe('optimize-chunk-assets handler', () => {
+          beforeEach(() => {
+            [compilationEventBinding] = compilationEventBindings;
+          });
+
+          it('binds to optimize-chunk-assets event', () => {
+            expect(compilationEventBinding.name).toEqual('optimize-chunk-assets');
+          });
+
+          it('only calls callback once', (done) => {
+            callback = jest.fn();
+            compilationEventBinding.handler([''], () => {
+              callback();
+              expect(callback.mock.calls.length).toBe(1);
+              done();
+            });
+          });
+
+          it('cache files', (done) => {
+            const files = ['test.js', 'test1.js', 'test2.js', 'test3.js'];
+
+            cacache.get = jest.fn(cacache.get);
+            cacache.put = jest.fn(cacache.put);
+
+            compilationEventBinding.handler([{
+              files,
+            }], () => {
+              // Try to found cached files, but we don't have their in cache
+              expect(cacache.get.mock.calls.length).toBe(4);
+              // Put files in cache
+              expect(cacache.put.mock.calls.length).toBe(4);
+
+              cacache
+                .ls(cacheDir)
+                .then((cacheEntriesList) => {
+                  const cacheKeys = Object.keys(cacheEntriesList);
+
+                  // Make sure that we cached files
+                  expect(cacheKeys.length).toBe(files.length);
+                  cacheKeys.forEach((cacheEntry) => {
+                    // eslint-disable-next-line no-new-func
+                    const cacheEntryOptions = new Function(`'use strict'\nreturn ${cacheEntry}`)();
+
+                    expect(cacheEntryOptions.myCacheKey).toBe(1);
+                    expect(cacheEntryOptions.myCacheKeyBasedOnFile).toMatch(/file-test(.)?\.js/);
+                    expect([cacheEntryOptions.path, cacheEntryOptions.hash])
+                      .toMatchSnapshot(cacheEntryOptions.path);
+                  });
+
+                  // Reset compilation assets and mocks
+                  compilation.assets = Object.assign({}, assets);
+                  compilation.errors = [];
+
+                  cacache.get.mockClear();
+                  cacache.put.mockClear();
+
+                  compilationEventBinding.handler([{
+                    files,
+                  }], () => {
+                    // Now we have cached files so we get their and don't put
+                    expect(cacache.get.mock.calls.length).toBe(4);
+                    expect(cacache.put.mock.calls.length).toBe(0);
+
+                    done();
+                  });
+                });
+            });
+          });
+        });
+      });
+    });
+
+    it('matches snapshot', () => {
+      const compiler = createCompiler();
+      new UglifyJsPlugin({
+        cache: true,
+        cacheKeys: (defaultCacheKeys, file) => {
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheKey = 1;
+          // eslint-disable-next-line no-param-reassign
+          defaultCacheKeys.myCacheLeyBasedOnFile = `file-${file}`;
+
+          return defaultCacheKeys;
+        },
+      }).apply(compiler);
+
+      return compile(compiler)
+        .then((stats) => {
+          const errors = stats.compilation.errors.map(cleanErrorStack);
+          const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+          expect(errors).toMatchSnapshot('errors');
+          expect(warnings).toMatchSnapshot('warnings');
+
+          for (const file in stats.compilation.assets) {
+            if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+              expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+            }
+          }
+        });
+    });
+  });
 });

diff --git a/test/minify.test.js b/test/minify.test.js
new file mode 100644
index 0000000..1552584
--- /dev/null
+++ b/test/minify.test.js
@@ -0,0 +1,170 @@
+import path from 'path';
+import uglifyJs from 'uglify-js';
+import uglifyEs from 'uglify-es';
+import terser from 'terser';
+import UglifyJsPlugin from '../src';
+import { cleanErrorStack, compile, createCompiler } from './helpers';
+
+describe('when applied with minify option', () => {
+  it('matches snapshot for `uglify-js` minifier', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/minify/es5.js`,
+      output: {
+        path: `${__dirname}/dist-uglify-js`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      minify(file) {
+        return uglifyJs.minify(file, {
+          mangle: {
+            reserved: ['baz'],
+          },
+        });
+      },
+    }).apply(compiler);
+
+    return compile(compiler)
+      .then((stats) => {
+        const errors = stats.compilation.errors.map(cleanErrorStack);
+        const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+        expect(errors).toMatchSnapshot('errors');
+        expect(warnings).toMatchSnapshot('warnings');
+
+        for (const file in stats.compilation.assets) {
+          if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+            expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+          }
+        }
+      });
+  });
+
+  it('matches snapshot for `uglify-es` minifier', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/minify/es6.js`,
+      output: {
+        path: `${__dirname}/dist-uglify-es`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      minify(file) {
+        return uglifyEs.minify(file, {
+          mangle: {
+            reserved: ['baz'],
+          },
+        });
+      },
+    }).apply(compiler);
+
+    return compile(compiler)
+      .then((stats) => {
+        const errors = stats.compilation.errors.map(cleanErrorStack);
+        const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+        expect(errors).toMatchSnapshot('errors');
+        expect(warnings).toMatchSnapshot('warnings');
+
+        for (const file in stats.compilation.assets) {
+          if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+            expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+          }
+        }
+      });
+  });
+
+  it('matches snapshot for `terser` minifier', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/minify/es6.js`,
+      output: {
+        path: `${__dirname}/dist-terser`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    new UglifyJsPlugin({
+      minify(file) {
+        return terser.minify(file, {
+          mangle: {
+            reserved: ['baz'],
+          },
+        });
+      },
+    }).apply(compiler);
+
+    return compile(compiler)
+      .then((stats) => {
+        const errors = stats.compilation.errors.map(cleanErrorStack);
+        const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+        expect(errors).toMatchSnapshot('errors');
+        expect(warnings).toMatchSnapshot('warnings');
+
+        for (const file in stats.compilation.assets) {
+          if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+            expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+          }
+        }
+      });
+  });
+
+  it('matches snapshot for `terser` minifier and `sourceMap: true`', () => {
+    const compiler = createCompiler({
+      entry: `${__dirname}/fixtures/minify/es6.js`,
+      output: {
+        path: `${__dirname}/dist-terser`,
+        filename: '[name].js',
+        chunkFilename: '[id].[name].js',
+      },
+    });
+
+    function removeAbsoluteSourceMapSources(source) {
+      if (source.map && source.map.sources) {
+        // eslint-disable-next-line no-param-reassign
+        source.map.sources = source.map.sources.map(sourceFromMap => path.relative(process.cwd(), sourceFromMap));
+      }
+
+      return source;
+    }
+
+    new UglifyJsPlugin({
+      sourceMap: true,
+      minify(file, sourceMap) {
+        const terserOption = {
+          mangle: {
+            reserved: ['baz'],
+          },
+        };
+
+        if (sourceMap) {
+          terserOption.sourceMap = {
+            content: sourceMap,
+          };
+        }
+
+        return terser.minify(file, terserOption);
+      },
+    }).apply(compiler);
+
+    return compile(compiler)
+      .then((stats) => {
+        const errors = stats.compilation.errors.map(cleanErrorStack);
+        const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+        expect(errors).toMatchSnapshot('errors');
+        expect(warnings).toMatchSnapshot('warnings');
+
+        for (const file in stats.compilation.assets) {
+          if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+            expect(removeAbsoluteSourceMapSources(stats.compilation.assets[file].sourceAndMap())).toMatchSnapshot(file);
+          }
+        }
+      });
+  });
+});

