diff --git a/test/cache-option.test.js b/test/cache-option.test.js
new file mode 100644
index 0000000..6a1f730
--- /dev/null
+++ b/test/cache-option.test.js
@@ -0,0 +1,604 @@
+import cacache from 'cacache';
+import findCacheDir from 'find-cache-dir';
+import UglifyJsPlugin from '../src/index';
+import {
+  PluginEnvironment,
+  createCompiler,
+  compile,
+  cleanErrorStack,
+} from './helpers';
+
+const cacheDir = findCacheDir({ name: 'uglifyjs-webpack-plugin' });
+
+describe('when options.cache', () => {
+  const assets = {
+    'test.js': {
+      source: () => 'function test(foo) { foo = 1; }',
+    },
+    'test1.js': {
+      source: () => 'function test1(foo) { foo = 1; }',
+    },
+    'test2.js': {
+      source: () => 'function test2(foo) { foo = 1; }',
+    },
+    'test3.js': {
+      source: () => 'function test3(foo) { foo = 1; }',
+    },
+  };
+
+  describe('false', () => {
+    let eventBindings;
+    let eventBinding;
