diff --git a/test/warningsFilter-option.test.js b/test/warningsFilter-option.test.js
new file mode 100644
index 0000000..5514558
--- /dev/null
+++ b/test/warningsFilter-option.test.js
@@ -0,0 +1,81 @@
+import UglifyJsPlugin from '../src/index';
+import {
+  cleanErrorStack,
+  createCompiler,
+  compile,
+} from './helpers';
+
+describe('when applied with `warningsFilter` option', () => {
+  let compiler;
+
+  beforeEach(() => {
+    compiler = createCompiler({
+      entry: {
+        one: `${__dirname}/fixtures/unreachable-code.js`,
+        two: `${__dirname}/fixtures/unreachable-code-2.js`,
+      },
+    });
+  });
+
+  it('matches snapshot for a `function` value and `sourceMap` is `true`', () => {
+    new UglifyJsPlugin({
+      warningsFilter(source) {
+        if (/unreachable-code-2\.js/.test(source)) {
+          return true;
+        }
+
+        return false;
+      },
+      uglifyOptions: {
+        warnings: true,
+      },
+      sourceMap: true,
+    }).apply(compiler);
+
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('errors');
+      expect(warnings).toMatchSnapshot('warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+        }
+      }
+    });
+  });
+
+  it('matches snapshot for a `function` value and `sourceMap` is `false`', () => {
+    new UglifyJsPlugin({
+      warningsFilter(source) {
+        if (/unreachable-code-2\.js/.test(source)) {
+          return true;
+        }
+
+        return false;
+      },
+      uglifyOptions: {
+        warnings: true,
+      },
+      sourceMap: false,
+    }).apply(compiler);
+
+
+    return compile(compiler).then((stats) => {
+      const errors = stats.compilation.errors.map(cleanErrorStack);
+      const warnings = stats.compilation.warnings.map(cleanErrorStack);
+
+      expect(errors).toMatchSnapshot('errors');
+      expect(warnings).toMatchSnapshot('warnings');
+
+      for (const file in stats.compilation.assets) {
+        if (Object.prototype.hasOwnProperty.call(stats.compilation.assets, file)) {
+          expect(stats.compilation.assets[file].source()).toMatchSnapshot(file);
+        }
+      }
+    });
+  });
+});

